ucs.kql:
// Windigo / Ebury — trojan libkeyutils.so or OpenSSH-suite tampering
// Defender for Endpoint Linux telemetry. Legit libkeyutils is ~10-12KB;
// Ebury samples are 50-150KB and dropped outside package-manager context.
let _pkg_managers = dynamic(["dpkg","apt","apt-get","yum","dnf","rpm","zypper","pacman","unattended-upgrade","update-alternatives","snapd","installer"]);
let _ebury_alt_libs  = dynamic(["libns2.so","libns5.so","libsbr.so","libpamc.so.0"]);
let _openssh_targets = dynamic(["/usr/sbin/sshd","/usr/bin/ssh","/usr/bin/ssh-add","/usr/bin/scp","/usr/libexec/openssh/sftp-server","/usr/lib/openssh/sftp-server"]);
DeviceFileEvents
| where Timestamp > ago(7d)
| where ActionType in ("FileCreated","FileModified","FileRenamed")
| where InitiatingProcessFileName !in~ (_pkg_managers)
| where ( FileName startswith "libkeyutils.so" and FileSize > 20000 )    // legit ~10-12KB
     or ( FolderPath in~ (_openssh_targets) )                              // direct OpenSSH binary touch
     or ( FileName in~ (_ebury_alt_libs) and FolderPath matches regex @"(?i)^/(usr/)?lib(64|x32)?(/|$)" )
| join kind=leftouter (
    DeviceInfo
    | where Timestamp > ago(1d)
    | summarize arg_max(Timestamp, OSPlatform, OSDistribution) by DeviceId
  ) on DeviceId
| project Timestamp, DeviceName, OSPlatform, OSDistribution,
          ActionType, FolderPath, FileName, FileSize, SHA256,
          InitiatingProcessFileName, InitiatingProcessCommandLine,
          InitiatingProcessAccountName, InitiatingProcessParentFileName
| order by Timestamp desc
